package pe.org.camaracomercioica.protestos.service;
import lombok.RequiredArgsConstructor; import org.springframework.beans.factory.annotation.Value; import org.springframework.security.access.AccessDeniedException; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import org.springframework.web.multipart.MultipartFile; import pe.org.camaracomercioica.protestos.dto.UploadResponse; import pe.org.camaracomercioica.protestos.exception.*; import pe.org.camaracomercioica.protestos.model.*; import pe.org.camaracomercioica.protestos.repository.*; import pe.org.camaracomercioica.protestos.util.UploadValidator; import java.io.IOException; import java.nio.file.*; import java.util.UUID;
@Service @RequiredArgsConstructor public class UploadService {private final DocumentoRepository documentos;private final CargaExcelRepository cargas;private final SolicitudRepository solicitudes;private final UsuarioRepository usuarios;@Value("${app.storage.location}") private String location;@Value("${app.storage.max-bytes:10485760}") private long maxBytes;
  @Transactional public UploadResponse documento(Long solicitudId,MultipartFile file,String email,boolean staff)throws IOException{new UploadValidator(maxBytes).validateDocument(file);var s=solicitudes.findById(solicitudId).orElseThrow(()->new ResourceNotFoundException("Solicitud no encontrada"));if(!staff&&!s.getSolicitante().getEmail().equalsIgnoreCase(email))throw new AccessDeniedException("No puede adjuntar documentos a esta solicitud");var stored=store(file);registrarLimpiezaRollback(stored);var d=new Documento();d.setSolicitud(s);d.setNombreOriginal(file.getOriginalFilename());d.setNombreAlmacenado(stored);d.setTipoContenido(file.getContentType());d.setTamano(file.getSize());d=documentos.save(d);return new UploadResponse(d.getId(),d.getNombreOriginal(),"RECIBIDO","Documento almacenado");}
  @Transactional public UploadResponse excel(MultipartFile file,String email)throws IOException{new UploadValidator(maxBytes).validateExcel(file);var u=usuarios.findByEmailIgnoreCase(email).orElseThrow(()->new ResourceNotFoundException("Usuario no encontrado"));var stored=store(file);registrarLimpiezaRollback(stored);var c=new CargaExcel();c.setUsuario(u);c.setNombreArchivo(file.getOriginalFilename());c.setNombreAlmacenado(stored);c.setEstado(EstadoCarga.RECIBIDA);c.setResumen("Archivo validado y registrado; importación pendiente");c=cargas.save(c);return new UploadResponse(c.getId(),c.getNombreArchivo(),c.getEstado().name(),c.getResumen());}
  private void registrarLimpiezaRollback(String stored){if(org.springframework.transaction.support.TransactionSynchronizationManager.isActualTransactionActive()){org.springframework.transaction.support.TransactionSynchronizationManager.registerSynchronization(new org.springframework.transaction.support.TransactionSynchronization(){@Override public void afterCompletion(int status){if(status==STATUS_ROLLED_BACK){try{Files.deleteIfExists(Paths.get(location).toAbsolutePath().normalize().resolve(stored));}catch(IOException ignored){}}}});}}
  private String store(MultipartFile file)throws IOException{var root=Paths.get(location).toAbsolutePath().normalize();Files.createDirectories(root);var original=file.getOriginalFilename();var ext=original.substring(original.lastIndexOf('.'));var name=UUID.randomUUID()+ext.toLowerCase();var target=root.resolve(name).normalize();if(!target.startsWith(root))throw new BadRequestException("Ruta de archivo inválida");try(var in=file.getInputStream()){Files.copy(in,target,StandardCopyOption.REPLACE_EXISTING);}return name;}}
